import React, { useEffect, useRef, useState } from 'react';
import { Mail, Camera, Clock, Calendar } from 'lucide-react';

const HomePage: React.FC = () => {
  const audioRef = useRef<HTMLAudioElement>(null);
  const [playing, setPlaying] = useState(false);
  const [visible, setVisible] = useState(false);
  const [audioUnlocked, setAudioUnlocked] = useState(false);

  useEffect(() => {
    setTimeout(() => setVisible(true), 200);
  }, []);

  /* Unlock audio after first user interaction (mobile-safe) */
  const unlockAudio = () => {
    if (!audioRef.current || audioUnlocked) return;

    audioRef.current
      .play()
      .then(() => {
        audioRef.current?.pause();
        setAudioUnlocked(true);
      })
      .catch(() => {});
  };

  const toggleAudio = () => {
    if (!audioRef.current) return;

    if (!audioUnlocked) {
      unlockAudio();
      return;
    }

    if (playing) {
      audioRef.current.pause();
      setPlaying(false);
    } else {
      audioRef.current.play().catch(() => {});
      setPlaying(true);
    }
  };

  const scrollTo = (id: string) => {
    document.getElementById(id)?.scrollIntoView({ behavior: 'smooth' });
  };

  const FloatingPetal = ({ style }: { style: React.CSSProperties }) => (
    <div
      style={{
        position: 'absolute',
        animation: 'petalFall 8s linear infinite',
        pointerEvents: 'none',
        ...style,
      }}
    >
      🌸
    </div>
  );

  return (
    <section
      id="home"
      onClick={unlockAudio}
      style={{
        minHeight: '100vh',
        background:
          'linear-gradient(160deg, #1a0500 0%, #3d0c02 25%, #5c1204 50%, #3d0c02 75%, #1a0500 100%)',
        display: 'flex',
        flexDirection: 'column',
        alignItems: 'center',
        justifyContent: 'center',
        position: 'relative',
        overflow: 'hidden',
        padding: '60px 20px',
      }}
    >
      {/* Audio */}
      <audio ref={audioRef} loop preload="auto">
        <source src="/audio/ma.mp3" type="audio/mpeg" />
      </audio>

      {/* Floating petals */}
      {[...Array(12)].map((_, i) => (
        <FloatingPetal
          key={i}
          style={{
            left: `${(i * 8.3) % 100}%`,
            top: '-5%',
            animationDelay: `${i * 0.7}s`,
            animationDuration: `${6 + (i % 4)}s`,
            fontSize: 14 + (i % 3) * 6,
            opacity: 0.6,
          }}
        />
      ))}

      {/* Main content */}
      <div
        style={{
          textAlign: 'center',
          maxWidth: 700,
          position: 'relative',
          zIndex: 1,
          opacity: visible ? 1 : 0,
          transform: visible ? 'translateY(0)' : 'translateY(30px)',
          transition: 'all 1.4s cubic-bezier(0.16, 1, 0.3, 1)',
        }}
      >
        {/* Tamil text */}
        <div
          style={{
            fontFamily: "'Noto Serif Tamil', serif",
            fontSize: 13,
            color: '#FFA07A',
            letterSpacing: '0.25em',
            marginBottom: 16,
          }}
        >
          ❁ அழைக்கின்றோம் ❁
        </div>

        {/* Om */}
        <div
          style={{
            fontFamily: 'serif',
            fontSize: 'clamp(3rem, 10vw, 6rem)',
            color: '#FFD700',
            lineHeight: 1,
            textShadow:
              '0 0 40px rgba(255,215,0,0.6), 0 0 80px rgba(255,107,53,0.3)',
            animation: 'omPulse 3s ease-in-out infinite',
          }}
        >
          ॐ
        </div>

        {/* Names */}
        <h1
          style={{
            fontFamily: "'Cormorant Garamond', serif",
            fontSize: 'clamp(2.8rem, 10vw, 5.5rem)',
            color: '#FFD700',
            fontStyle: 'italic',
            fontWeight: 300,
            lineHeight: 1.05,
            marginBottom: 12,
          }}
        >
          Nagamani
          <br />
          <span
            style={{
              fontSize: '0.45em',
              letterSpacing: '0.5em',
              color: '#FFA07A',
              display: 'block',
            }}
          >
            &
          </span>
          Kirthika
        </h1>

        {/* Tagline */}
        <div
          style={{
            fontFamily: "'Cormorant Garamond', serif",
            fontSize: 'clamp(0.85rem, 2.5vw, 1.15rem)',
            color: 'rgba(255,215,0,0.7)',
            letterSpacing: '0.35em',
            marginBottom: 40,
          }}
        >
          WEDDING INVITATION
        </div>

        {/* Buttons */}
        <div
          style={{
            display: 'flex',
            gap: 16,
            flexWrap: 'wrap',
            justifyContent: 'center',
            marginBottom: 40,
          }}
        >
          {[
            { label: 'View Invitation', icon: <Mail size={18} />, target: 'invitation' },
            { label: 'Gallery', icon: <Camera size={18} />, target: 'gallery' },
            { label: 'Countdown', icon: <Clock size={18} />, target: 'countdown' },
          ].map(btn => (
            <button
              key={btn.label}
              onClick={() => scrollTo(btn.target)}
              style={{
                fontFamily: "'Cormorant Garamond', serif",
                fontSize: 14,
                letterSpacing: '0.2em',
                padding: '12px 24px',
                background: 'transparent',
                border: '1.5px solid rgba(255,215,0,0.5)',
                color: '#FFD700',
                borderRadius: 4,
                cursor: 'pointer',
              }}
            >
              {btn.icon} {btn.label}
            </button>
          ))}
        </div>

        {/* Tap hint */}
        {!audioUnlocked && (
          <div
            style={{
              fontSize: 12,
              color: '#FFD700',
              opacity: 0.7,
              letterSpacing: '0.2em',
            }}
          >
            TAP ANYWHERE TO PLAY MUSIC
          </div>
        )}
      </div>

      {/* Music button */}
      <button
        onClick={toggleAudio}
        title={playing ? 'Pause Music' : 'Play Music'}
        style={{
          position: 'fixed',
          bottom: 28,
          right: 28,
          width: 52,
          height: 52,
          borderRadius: '50%',
          background: 'linear-gradient(135deg, #8B0000, #cc2200)',
          border: '2px solid rgba(255,215,0,0.6)',
          color: '#FFD700',
          fontSize: 20,
          cursor: 'pointer',
          zIndex: 100,
        }}
      >
        {playing ? '🎵' : '🎶'}
      </button>

      <style>{`
        @keyframes petalFall {
          0% { transform: translateY(-20px) rotate(0deg); opacity: 0; }
          100% { transform: translateY(110vh) rotate(720deg); opacity: 0; }
        }
        @keyframes omPulse {
          0%, 100% { transform: scale(1); }
          50% { transform: scale(1.06); }
        }
      `}</style>
    </section>
  );
};

export default HomePage;
